code = """import json, re
import pandas as pd

business_file = var_call_glKA8W8O9XQpL6skMLeTPrBG
review_file = var_call_Yq9r2lFTFDEhJb5LK7Hi8IAf

with open(business_file,'r',encoding='utf-8') as f:
    businesses = json.load(f)
with open(review_file,'r',encoding='utf-8') as f:
    reviews = json.load(f)

df_b = pd.DataFrame(businesses)
df_r = pd.DataFrame(reviews)

# list of US state codes
states = set(['AL','AK','AZ','AR','CA','CO','CT','DE','FL','GA','HI','ID','IL','IN','IA','KS','KY','LA','ME','MD','MA','MI','MN','MS','MO','MT','NE','NV','NH','NJ','NM','NY','NC','ND','OH','OK','OR','PA','RI','SC','SD','TN','TX','UT','VT','VA','WA','WV','WI','WY'])

patterns = [re.compile(r",\s*([A-Z]{2}),"), re.compile(r",\s*([A-Z]{2})\b"), re.compile(r"\b([A-Z]{2})\b")]

def extract_state(desc):
    if not isinstance(desc, str):
        return None
    for p in patterns:
        m = p.search(desc)
        if m:
            code = m.group(1)
            if code in states:
                return code
    return None

if 'description' in df_b.columns:
    df_b['state'] = df_b['description'].apply(extract_state)
else:
    df_b['state'] = None

# Prepare reviews
if 'business_ref' in df_r.columns:
    df_r['business_id'] = df_r['business_ref'].astype(str).str.replace('businessref_', 'businessid_', regex=False)
else:
    df_r['business_id'] = None

if 'rating' in df_r.columns:
    df_r['rating'] = pd.to_numeric(df_r['rating'], errors='coerce')
else:
    df_r['rating'] = pd.NA

# Merge
merged = df_r.merge(df_b[['business_id','state']], on='business_id', how='left')
merged = merged[merged['state'].notna()]

if merged.empty:
    result = {"state": None, "total_reviews": 0, "avg_rating": None}
else:
    grp = merged.groupby('state').agg(total_reviews=('rating','count'), avg_rating=('rating','mean')).reset_index()
    grp = grp.sort_values(['total_reviews','state'], ascending=[False,True]).reset_index(drop=True)
    top = grp.loc[0]
    result = {"state": str(top['state']), "total_reviews": int(top['total_reviews']), "avg_rating": float(round(top['avg_rating'],3))}

print('__RESULT__:')
print(json.dumps(result))"""

